-- prdb.taat_innovation_development_view (final - P2-3064)
-- Changes:
--   1. WHERE rule 3: require at least one African country via clarisa_countries.iso_alpha_2
--   2. JSON regions: only African um49Codes (2, 11, 14, 15, 17, 18, 202)
--   3. JSON countries: only African iso_alpha_2 (clarisa_country_regions is empty)
--   4. pdf_link: reporting result details URL using result_code + version_id
--
-- Apply equivalent changes to taat_innovation_use_view and taat_innovation_package_view.

CREATE OR REPLACE
ALGORITHM = UNDEFINED VIEW `taat_innovation_development_view` AS
select
    json_object('id', `r`.`id`, 'result_code', `r`.`result_code`, 'result_year',(select `v`.`phase_year` from `version` `v` where (`v`.`id` = `r`.`version_id`)), 'commercial_name', `r`.`title`, 'technology_name', `rid`.`short_title`, 'slogan', 'N/A', 'contact_person_name', `r`.`lead_contact_person`, 'contact_person_email', `r`.`lead_contact_person`, 'description', `r`.`description`, 'associated_technology',(select coalesce(json_arrayagg(json_object('result_code', `r2`.`result_code`, 'title', `r2`.`title`)), json_array()) from (`result` `r2` join `linked_result` `lr2` on((`lr2`.`linked_results_id` = `r2`.`id`))) where (`lr2`.`origin_result_id` = `r`.`id`)), 'intellectual_property',(select coalesce(json_arrayagg(json_object('question', `level2_questions`.`question_text`, 'answer', `level2_questions`.`selected_answer`)), json_array('Not applicable')) from (select distinct `rq_level2`.`question_text` AS `question_text`, `rq_level3`.`question_text` AS `selected_answer` from ((`result_answers` `ra` join `result_questions` `rq_level3` on((`ra`.`result_question_id` = `rq_level3`.`result_question_id`))) join `result_questions` `rq_level2` on((`rq_level3`.`parent_question_id` = `rq_level2`.`result_question_id`))) where ((`ra`.`result_id` = `r`.`id`) and (`ra`.`is_active` = true) and (`ra`.`answer_boolean` = true) and (`rq_level2`.`parent_question_id` = 26))) `level2_questions`), 'end_users', json_object('actors',(select coalesce(json_arrayagg(json_object('actor_type', `at`.`name`, 'other_actor_type',(case when (`ra`.`actor_type_id` = 5) then `ra`.`other_actor_type` else NULL end), 'women',(case when (`ra`.`sex_and_age_disaggregation` <> 1) then ifnull(`ra`.`women`, 0) else NULL end), 'women_youth',(case when (`ra`.`sex_and_age_disaggregation` <> 1) then ifnull(`ra`.`women_youth`, 0) else NULL end), 'men',(case when (`ra`.`sex_and_age_disaggregation` <> 1) then ifnull(`ra`.`men`, 0) else NULL end), 'men_youth',(case when (`ra`.`sex_and_age_disaggregation` <> 1) then ifnull(`ra`.`men_youth`, 0) else NULL end), 'how_many', ifnull(`ra`.`how_many`, 0), 'sex_age_disaggregation_applies',(`ra`.`sex_and_age_disaggregation` <> 1))), json_array('Not applicable')) from (`result_actors` `ra` left join `actor_type` `at` on((`ra`.`actor_type_id` = `at`.`actor_type_id`))) where ((`ra`.`result_id` = `r`.`id`) and (`ra`.`is_active` = 1))), 'organizations',(select coalesce(json_arrayagg(json_object('institution_type', `cit`.`name`, 'other_institution',(case when (`rbit`.`institution_types_id` = 78) then `rbit`.`other_institution` else NULL end), 'how_many', `rbit`.`how_many`, 'graduate_students', `rbit`.`graduate_students`)), json_array('Not applicable')) from (`results_by_institution_type` `rbit` left join `clarisa_institution_types` `cit` on((`rbit`.`institution_types_id` = `cit`.`code`))) where ((`rbit`.`results_id` = `r`.`id`) and (`rbit`.`is_active` = 1) and (`rbit`.`institution_roles_id` = 5))), 'other_quantitative',(select coalesce(json_arrayagg(json_object('unit_of_measure', `rim`.`unit_of_measure`, 'quantity', `rim`.`quantity`)), json_array('Not applicable')) from `result_ip_measure` `rim` where ((`rim`.`result_id` = `r`.`id`) and (`rim`.`is_active` = 1)))), 'where_has_the_technology', json_object('geographic_focus',(select `cgs`.`name` from `clarisa_geographic_scope` `cgs` where (`r`.`geographic_scope_id` = `cgs`.`id`)), 'regions',(case when (`r`.`has_regions` = 1) then (select coalesce(json_arrayagg(`cr`.`name`), json_array()) from (`result_region` `rg` left join `clarisa_regions` `cr` on((`rg`.`region_id` = `cr`.`um49Code`))) where ((`rg`.`result_id` = `r`.`id`) and (`rg`.`is_active` = 1) and (`rg`.`region_id` in (2, 11, 14, 15, 17, 18, 202)))) else json_array('Not applicable') end), 'countries',(case when (`r`.`has_countries` = 1) then (select coalesce(json_arrayagg(`cc`.`name`), json_array()) from (`result_country` `rc` inner join `clarisa_countries` `cc` on((`rc`.`country_id` = `cc`.`id`))) where ((`rc`.`result_id` = `r`.`id`) and (`rc`.`is_active` = 1) and (`cc`.`iso_alpha_2` in ('DZ','AO','BJ','BW','BF','BI','CV','CM','CF','TD','KM','CG','CD','CI','DJ','EG','GQ','ER','SZ','ET','GA','GM','GH','GN','GW','KE','LS','LR','LY','MG','MW','ML','MR','MU','MA','MZ','NA','NE','NG','RW','ST','SN','SC','SL','SO','ZA','SS','SD','TZ','TG','TN','UG','ZM','ZW','EH')))) else json_array('Not applicable') end)), 'sdg',(case when (`r`.`result_level_id` in (1, 2)) then (select coalesce(json_arrayagg(json_object('sdg_target_code', `cst`.`sdg_target_code`, 'sdg_target', `cst`.`sdg_target`)), json_array('Not applicable')) from (`result_sdg_targets` `rst` left join `clarisa_sdgs_targets` `cst` on((`rst`.`clarisa_sdg_target_id` = `cst`.`id`))) where ((`rst`.`result_id` = `r`.`id`) and (`rst`.`is_active` = 1))) else (select coalesce(json_arrayagg(json_object('sdg_target_code', `cst`.`sdg_target_code`, 'sdg_target', `cst`.`sdg_target`)), json_array('Not applicable')) from ((`result_toc_sdg_targets` `rtst` left join `clarisa_sdgs_targets` `cst` on((`rtst`.`clarisa_sdg_target_id` = `cst`.`id`))) left join `results_toc_result` `rtr` on(((`rtr`.`results_id` = `r`.`id`) and (`rtr`.`is_active` = 1)))) where ((`rtst`.`result_toc_result_id` = `rtr`.`result_toc_result_id`) and (`rtst`.`is_active` = 1))) end), 'dac_score', json_array(json_object('name', 'gender_assessment', 'description',(select `gtl`.`description` from `gender_tag_level` `gtl` where (`gtl`.`id` = `r`.`gender_tag_level_id`)), 'evidence_links',(select coalesce(json_arrayagg(`e1`.`link`), json_array()) from `evidence` `e1` where ((`e1`.`result_id` = `r`.`id`) and (`e1`.`is_active` = 1) and (`e1`.`gender_related` = 1)))), json_object('name', 'climate_adaptability', 'description',(select `gtl`.`description` from `gender_tag_level` `gtl` where (`gtl`.`id` = `r`.`climate_change_tag_level_id`)), 'evidence_links',(select coalesce(json_arrayagg(`e1`.`link`), json_array()) from `evidence` `e1` where ((`e1`.`result_id` = `r`.`id`) and (`e1`.`is_active` = 1) and (`e1`.`youth_related` = 1)))), json_object('name', 'environment_biodiversity', 'description',(select `gtl`.`description` from `gender_tag_level` `gtl` where (`gtl`.`id` = `r`.`environmental_biodiversity_tag_level_id`)), 'evidence_links',(select coalesce(json_arrayagg(`e1`.`link`), json_array()) from `evidence` `e1` where ((`e1`.`result_id` = `r`.`id`) and (`e1`.`is_active` = 1) and (`e1`.`environmental_biodiversity_related` = 1)))), json_object('name', 'nutrition_health', 'description',(select `gtl`.`description` from `gender_tag_level` `gtl` where (`gtl`.`id` = `r`.`nutrition_tag_level_id`)), 'evidence_links',(select coalesce(json_arrayagg(`e1`.`link`), json_array()) from `evidence` `e1` where ((`e1`.`result_id` = `r`.`id`) and (`e1`.`is_active` = 1) and (`e1`.`nutrition_related` = 1)))), json_object('name', 'poverty_reduction', 'description',(select `gtl`.`description` from `gender_tag_level` `gtl` where (`gtl`.`id` = `r`.`poverty_tag_level_id`)), 'evidence_links',(select coalesce(json_arrayagg(`e1`.`link`), json_array()) from `evidence` `e1` where ((`e1`.`result_id` = `r`.`id`) and (`e1`.`is_active` = 1) and (`e1`.`poverty_related` = 1))))), 'cost', json_object('initiatives_investment',(select coalesce(json_arrayagg(json_object('official_code', `ci9`.`official_code`, 'name', `ci9`.`name`, 'total_value',(case when (`rib`.`is_determined` = 1) then 'This yet to be determinated' else concat('Total USD Value (in-cash + in-kind): ', `rib`.`kind_cash`) end))), json_array('Not applicable')) from ((`result_initiative_budget` `rib` left join `results_by_inititiative` `rbi9` on((`rbi9`.`id` = `rib`.`result_initiative_id`))) left join `clarisa_initiatives` `ci9` on((`rbi9`.`inititiative_id` = `ci9`.`id`))) where ((`rib`.`is_active` = 1) and (`rbi9`.`result_id` = `r`.`id`) and (`rbi9`.`is_active` = 1))), 'npp_investment',(select coalesce(json_arrayagg(json_object('grant_title', `npp`.`grant_title`, 'total_value',(case when (`nppb`.`is_determined` = 1) then 'This yet to be determinated' else concat('Total USD Value (in-cash + in-kind) ', `nppb`.`kind_cash`) end))), json_array('Not applicable')) from (`non_pooled_projetct_budget` `nppb` left join `non_pooled_project` `npp` on((`npp`.`id` = `nppb`.`non_pooled_projetct_id`))) where ((`nppb`.`is_active` = 1) and (`npp`.`is_active` = 1) and (`npp`.`results_id` = `r`.`id`))), 'partner_investment',(select coalesce(json_arrayagg(json_object('institution_name', `ci8`.`name`, 'total_value',(case when (`rib8`.`is_determined` = 1) then 'This yet to be determinated' else concat('Total USD Value (in-cash + in-kind): ', `rib8`.`kind_cash`) end))), json_array('Not applicable')) from ((`result_institutions_budget` `rib8` left join `results_by_institution` `rbi8` on((`rbi8`.`id` = `rib8`.`result_institution_id`))) left join `clarisa_institutions` `ci8` on((`rbi8`.`institutions_id` = `ci8`.`id`))) where ((`rib8`.`is_active` = 1) and (`rbi8`.`result_id` = `r`.`id`) and (`rbi8`.`is_active` = 1)))), 'idea_maturity_level_of_use', 'N/A', 'scalling_readiness_reference', json_object('id', `cirl`.`id`, 'name', `cirl`.`name`, 'definition', `cirl`.`definition`, 'level', `cirl`.`level`), 'pdf_link', concat('https://reporting.cgiar.org/reports/result-details/', `r`.`result_code`, '?phase=', `r`.`version_id`)) AS `innovation_data`
from
    (((`result` `r`
join `result_type` `rt` on
    ((`rt`.`id` = `r`.`result_type_id`)))
join `results_innovations_dev` `rid` on
    ((`rid`.`results_id` = `r`.`id`)))
left join `clarisa_innovation_readiness_level` `cirl` on
    ((`cirl`.`id` = `rid`.`innovation_readiness_level_id`)))
where
    ((`r`.`status_id` = 2)
        and (`r`.`result_type_id` = 7)
            and (`r`.`is_active` = 1)
                and (((`r`.`has_regions` = 1)
                    and exists(select 1 from `result_region` `rr` where ((`rr`.`result_id` = `r`.`id`) and (`rr`.`is_active` = 1) and (`rr`.`region_id` in (2, 11, 14, 15, 17, 18, 202)))))
                    or ((`r`.`geographic_scope_id` = 2)
                        and exists(select 1 from `result_region` `rr` where ((`rr`.`result_id` = `r`.`id`) and (`rr`.`is_active` = 1) and (`rr`.`region_id` in (2, 11, 14, 15, 17, 18, 202)))))
                        or ((`r`.`has_countries` = 1)
                            and (`r`.`geographic_scope_id` in (3, 4, 5))
                            and exists(
                                select 1
                                from `result_country` `rc`
                                inner join `clarisa_countries` `cc` on ((`rc`.`country_id` = `cc`.`id`))
                                where ((`rc`.`result_id` = `r`.`id`)
                                    and (`rc`.`is_active` = 1)
                                    and (`cc`.`iso_alpha_2` in ('DZ','AO','BJ','BW','BF','BI','CV','CM','CF','TD','KM','CG','CD','CI','DJ','EG','GQ','ER','SZ','ET','GA','GM','GH','GN','GW','KE','LS','LR','LY','MG','MW','ML','MR','MU','MA','MZ','NA','NE','NG','RW','ST','SN','SC','SL','SO','ZA','SS','SD','TZ','TG','TN','UG','ZM','ZW','EH')))
                            )))));

